#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 10;
vector<bool> vis(N, false);
vector<pair<int,int>> adj[N];

void prims(int source, int n) { 
    long long ans = 0; // Total weight of the MST

    priority_queue<vector<int>> pq;

    pq.push({0, source}); 

    while(pq.size() != 0) {
        vector<int> node = pq.top();
        pq.pop();

        int v = node[1];

        if(vis[v]) {
            continue;
        }

        ans += -node[0]; // Add the edge weight to answer

        vis[v] = 1; // Mark vertes as processed

        for(auto edge: adj[v]) {
            pq.push({-edge.second, edge.first, v});   
        }
    }      

    cout << ans << "\n"; 
}


int main() {
    int n, m;
    cin >> n >> m;

    for(int i = 0; i < m; i++) {
        int x, y, w;
        cin >> x >> y >> w;
        adj[x].push_back({y, w});
        adj[y].push_back({x, w});
    }

    prims(1, n);

    return 0;
}

